// Daily cap + balance across archetypes. Rows with status blank or 'queued' qualify.
const MAX_PER_RUN = 6;
const rows = $input.all().map(function (i) { return i.json; });

const queued = rows.filter(function (r) {
  const status = String(r.status || '').trim().toLowerCase();
  const email = String(r.email || '').trim();
  return (status === '' || status === 'queued') && email.indexOf('@') !== -1;
});

const buckets = { services: [], trades: [], sales: [], other: [] };
for (const r of queued) {
  const a = String(r.archetype || 'other').trim().toLowerCase();
  (buckets[a] || buckets.other).push(r);
}

const order = ['services', 'trades', 'sales', 'other'];
const interleaved = [];
let added = true;
while (added) {
  added = false;
  for (const a of order) {
    if (buckets[a].length) { interleaved.push(buckets[a].shift()); added = true; }
  }
}

return interleaved.slice(0, MAX_PER_RUN).map(function (r) { return { json: r }; });

// Fetch Layer 1 brain once, build a prospect-qualifier request per prospect.
const repo = 'https://raw.githubusercontent.com/isaiahwong-bit/Digital-Artifacts';
const refs = ['main', 'feat/sales-ops-automation'];
const files = ['icp', 'outbound-icp', 'outbound-offer', 'tone-of-voice', 'company-brief'];

const brain = {};
for (const f of files) {
  let got = null;
  for (const ref of refs) {
    try {
      got = await this.helpers.httpRequest({
        method: 'GET',
        url: repo + '/' + ref + '/brain/' + f + '.md',
        encoding: 'text',
        json: false,
      });
      break;
    } catch (e) { got = null; }
  }
  if (got === null) throw new Error('Brain file unreachable on any branch: ' + f);
  brain[f] = got;
}

const qualifierSystem = 'You are the Digital Artifacts outbound prospect-qualifier (Layer 2 skill). Decide if this business and contact are a defensible cold-outreach target under Australian Spam Act inferred-consent rules. Be strict: a smaller list of real fits beats a big list of forced ones. Never invent a pain that is not supportable from the prospect notes. Return strictly the JSON schema, nothing else, no prose, no markdown fences.';

const schemaLine = '{"fit":"strong|plausible|weak|not_fit","archetype":"services|trades|sales|other","role_relevant":true|false,"address_conspicuous":true|false,"likely_pain":"one specific repetitive weekly task this role almost certainly deals with, or empty if none can be named honestly","pain_evidenced":true|false,"disqualifiers":[],"first_name":"contact first name only","reason":"one sentence on why this grade","recommended_action":"draft_opener|manual_review|drop"}';

const items = $input.all();

return items.map(function (it, idx) {
  const p = it.json;
  const content = '<outbound_icp>\n' + brain['outbound-icp'] + '\n</outbound_icp>\n\n'
    + '<inbound_icp>\n' + brain['icp'] + '\n</inbound_icp>\n\n'
    + '<prospect>\n'
    + 'Business name: ' + (p.business_name || '') + '\n'
    + 'Industry / description: ' + (p.industry || p.archetype || '') + '\n'
    + 'Approx size: ' + (p.size || '') + '\n'
    + 'Country / location: ' + (p.location || '') + '\n'
    + 'Contact name: ' + (p.contact_name || '') + '\n'
    + 'Contact role: ' + (p.contact_role || '') + '\n'
    + 'Email: ' + (p.email || '') + '\n'
    + 'Where the email was published: ' + (p.email_source || '') + '\n'
    + 'Public footprint notes: ' + (p.notes || '') + '\n'
    + '</prospect>\n\n'
    + 'Return strictly this JSON, nothing else:\n' + schemaLine;
  const qualifier_body = {
    model: 'claude-sonnet-4-6',
    max_tokens: 600,
    system: qualifierSystem,
    messages: [{ role: 'user', content: content }],
  };
  return { json: { ...p, brain: brain, qualifier_body: qualifier_body }, pairedItem: { item: idx } };
});

// Parse the qualifier verdict, set the route, build the cold-opener request.
const prev = $('Prep Brain + Qualifier Bodies').item.json;
const raw = ($json && $json.content && $json.content[0] && $json.content[0].text) || '';

let q;
try {
  const s = raw.indexOf('{');
  const e = raw.lastIndexOf('}');
  q = JSON.parse(raw.slice(s, e + 1));
} catch (err) {
  q = {
    fit: 'not_fit', archetype: prev.archetype || 'other',
    role_relevant: false, address_conspicuous: false,
    likely_pain: '', pain_evidenced: false,
    disqualifiers: ['qualifier_parse_failed'],
    first_name: String(prev.contact_name || '').split(' ')[0],
    reason: 'Qualifier response could not be parsed. Dropped for safety.',
    recommended_action: 'drop',
  };
}

const route = (q.recommended_action === 'draft_opener' || q.recommended_action === 'manual_review')
  ? q.recommended_action : 'drop';

const openerSystem = 'You are drafting a cold opening email from Isaiah at Digital Artifacts. This is the salt in a salty-pretzel approach: it offers something genuinely useful nearly free and does NOT pitch. HARD RULES: no em dashes ever, use a comma or period or colon or parenthesis instead. Open with the first name then a comma then go straight in, no greeting line, no introduction of who we are. body_plain is under 90 words excluding the footer. Exactly one call to action: reply with the one task eating the most time. No booking link, no description of the 4 layers, no pricing. Never claim a result, client or statistic that is not in the company brief. Sign off Isaiah only. End body_plain with the token {{ SENDER_FOOTER }} on its own final line. Return JSON only, no prose, no markdown fences.';

const b = prev.brain || {};
const openerSchema = '{"subject":"short, lowercase-feeling, not salesy, references their world not ours","body_plain":"the email as plain text, short, ends with {{ SENDER_FOOTER }} on its own final line","names_specific_pain":true|false,"word_count":0,"confidence":"high|medium|low","notes_for_isaiah":"one sentence: what pain it leans on and why this prospect"}';

const content = '<offer>\n' + (b['outbound-offer'] || '') + '\n</offer>\n\n'
  + '<tone>\n' + (b['tone-of-voice'] || '') + '\n</tone>\n\n'
  + '<company>\n' + (b['company-brief'] || '') + '\n</company>\n\n'
  + '<prospect>\n'
  + 'Business: ' + (prev.business_name || '') + '\n'
  + 'Contact: ' + (q.first_name || '') + ' (' + (prev.contact_role || '') + ')\n'
  + 'Archetype: ' + (q.archetype || '') + '\n'
  + 'Likely pain: ' + (q.likely_pain || '') + '\n'
  + 'Public footprint notes: ' + (prev.notes || '') + '\n'
  + '</prospect>\n\n'
  + 'Write the opener. Return strictly this JSON, nothing else:\n' + openerSchema;

const opener_body = {
  model: 'claude-sonnet-4-6',
  max_tokens: 700,
  system: openerSystem,
  messages: [{ role: 'user', content: content }],
};

return { json: { ...prev, qualification: q, route: route, opener_body: opener_body } };

// Parse the opener, inject the Spam Act compliance footer, build the sheet row.
const prev = $('Parse Qualification + Opener Body').item.json;
const raw = ($json && $json.content && $json.content[0] && $json.content[0].text) || '';

let opener;
try {
  const s = raw.indexOf('{');
  const e = raw.lastIndexOf('}');
  opener = JSON.parse(raw.slice(s, e + 1));
} catch (err) {
  opener = {
    subject: '', body_plain: '', names_specific_pain: false,
    word_count: 0, confidence: 'low',
    notes_for_isaiah: 'Opener response could not be parsed. Do not approve, regenerate this one.',
  };
}

const q = prev.qualification || {};

const unsubUrl = 'https://digitalartifacts.com.au/unsubscribe?id='
  + encodeURIComponent(prev.prospect_id || '') + '&list=outbound';
const roleBit = prev.contact_role
  ? (prev.contact_role + ' is the publicly listed contact for ' + (prev.business_name || 'your business'))
  : ('this address is publicly listed for ' + (prev.business_name || 'your business'));
const footer = ',\n,\nDigital Artifacts, Sydney NSW, Australia. Sent by Isaiah Wong, isaiah@digitalartifacts.com.au\n'
  + 'You received this one message because ' + roleBit + ', and it relates to that role. '
  + 'Not interested? Reply with the word unsubscribe, or use this link: ' + unsubUrl + '. '
  + 'You will be removed straight away and never contacted again.';

let body = String(opener.body_plain || '');
if (body.indexOf('{{ SENDER_FOOTER }}') !== -1) {
  body = body.split('{{ SENDER_FOOTER }}').join(footer);
} else if (body.indexOf('{{SENDER_FOOTER}}') !== -1) {
  body = body.split('{{SENDER_FOOTER}}').join(footer);
} else {
  body = body.replace(/\s*$/, '') + '\n' + footer;
}
body = body.replace(/—|–/g, ',');
opener.body_plain = body;

const nowIso = new Date().toISOString();

const sheet_row = {
  prospect_id: prev.prospect_id || '',
  status: 'awaiting_approval',
  fit: q.fit || '',
  role_relevant: q.role_relevant === true ? 'yes' : 'no',
  likely_pain: q.likely_pain || '',
  opener_subject: opener.subject || '',
  opener_body: opener.body_plain || '',
  opener_confidence: opener.confidence || '',
  opener_word_count: opener.word_count || '',
  notes_for_isaiah: opener.notes_for_isaiah || '',
  qualified_at: nowIso,
};

return { json: {
  prospect_id: prev.prospect_id || '',
  business_name: prev.business_name || '',
  contact_name: prev.contact_name || '',
  contact_role: prev.contact_role || '',
  email: prev.email || '',
  archetype: q.archetype || prev.archetype || '',
  qualification: q,
  opener: opener,
  sheet_row: sheet_row,
} };

// Build the Telegram approval brief for one drafted cold opener.
const d = $json;
const q = d.qualification || {};
const o = d.opener || {};
const fitIcon = q.fit === 'strong' ? '🟢' : (q.fit === 'plausible' ? '🟡' : '⚪');
const arche = String(q.archetype || d.archetype || 'other').toUpperCase();

const text = '📤 COLD OPENER  ' + fitIcon + ' ' + String(q.fit || '').toUpperCase() + ' - ' + arche + '\n\n'
  + (d.business_name || '') + '\n'
  + (d.contact_name || 'no name') + ' - ' + (d.contact_role || 'no role') + '\n'
  + (d.email || '') + '\n\n'
  + 'LIKELY PAIN\n' + (q.likely_pain || 'none named') + '\n\n'
  + '-------\n'
  + 'DRAFT (' + (o.word_count || '?') + ' words, ' + (o.confidence || '?') + ' confidence)\n\n'
  + 'Subject: ' + (o.subject || '') + '\n\n'
  + (o.body_plain || '') + '\n\n'
  + '-------\n'
  + (o.notes_for_isaiah || 'No notes.');

return { json: { prospect_id: d.prospect_id, telegram_text: text.slice(0, 3900) } };

// Weak fit: park it in the sheet for a human look, never auto-draft.
const d = $json;
const q = d.qualification || {};
return { json: {
  prospect_id: d.prospect_id || '',
  status: 'manual_review',
  fit: q.fit || '',
  role_relevant: q.role_relevant === true ? 'yes' : 'no',
  likely_pain: q.likely_pain || '',
  notes_for_isaiah: q.reason || 'Weak fit, needs a human look.',
  qualified_at: new Date().toISOString(),
} };

// Not a fit, or qualifier failed: log the reason and drop.
const d = $json;
const q = d.qualification || {};
const reason = q.reason || (Array.isArray(q.disqualifiers) ? q.disqualifiers.join('; ') : '');
return { json: {
  prospect_id: d.prospect_id || '',
  status: 'not_fit',
  fit: q.fit || 'not_fit',
  notes_for_isaiah: reason || 'Did not pass the qualifier.',
  qualified_at: new Date().toISOString(),
} };
